            inv.setItem(slot, head);
            slot++;
        }
        if (slot == 0) {
            inv.setItem(22, makePlain(Material.BARRIER, "§7No bots available",
                    List.of("§7Spawn a bot first")));
        }
    }

    private void populatePathsPage(Inventory inv) {
