            int deleted = ps.executeUpdate();
            if (deleted > 0) {
                org.bukkit.Bukkit.getLogger().info("[PvPBot Stats] Cleaned up " + deleted + " old records");
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}
